def eulerian_num(n, m):
    if m >= n or m < 0:
        return 0
    if m == 0:
        return 1
    if m == n - 1:
        return 1

    # Using the recurrence relation: A(n,m) = (n-m)*A(n-1,m-1) + (m+1)*A(n-1,m)
    # We'll use dynamic programming to avoid recomputation
    dp = [[0 for _ in range(m + 1)] for _ in range(n + 1)]

    # Base case
    for i in range(n + 1):
        dp[i][0] = 1

    # Fill the dp table
    for i in range(1, n + 1):
        for j in range(1, min(i, m + 1)):
            dp[i][j] = (i - j) * dp[i - 1][j - 1] + (j + 1) * dp[i - 1][j]

    return dp[n][m]

